SELECT AVG(prcp) AS average_precipitation
FROM weather_observations
WHERE station_id = 0 AND observation_date LIKE '2023-06-%';

SELECT MAX(tmax) AS max_temperature
FROM weather_observations
WHERE station_id = 0;

SELECT MAX(forecast_date)
FROM weather_forecasts
WHERE station_id = 0;

SELECT observation_date, tmax
FROM weather_observations
WHERE observation_date LIKE '2018-%';

SELECT observation_id, station_id, observation_date, tmax, tmin
FROM weather_observations
ORDER BY observation_date DESC;

SELECT AVG(tobs) AS average_temperature
FROM weather_observations
WHERE station_id = 0;
